    int Scheduler::get_highest_proirity()
    {
        _sche_lock.acquire();
        int prio = lowest_proc_prio;
        for (Pcb &p : k_proc_pool)
        {
            if (p._priority < prio && p._state == ProcState::RUNNABLE)
            {
                prio = p._priority;
            }
        }
        _sche_lock.release();
        return prio;
    }

    void Scheduler::start_schedule()
    {
