	int DeviceManager::search_device(const char *name)
	{
		for (int i = 0; i < DEV_TBL_LEN; ++i)
		{
			DeviceTableEntry &te = _device_table[i];
			if (te.device_ptr == nullptr)
				continue;
			if (te.device_ptr->type() == dev_unknown)
				continue;
			if (strcmp(name, te.device_name) == 0)
				return i;
		}
		return -1;
	}

