    {
        if (_is_bound) {
            return -1; // 已绑定
        }

        // 从当前进程获取文件对象
        auto pcb = proc::k_pm.get_cur_pcb();
        if (!pcb) {
            return -1;
        }

        auto file = pcb->get_open_file(fd);
        if (!file) {
            return -1; // 无效的文件描述符
        }

        // 检查文件类型

        printfGreen("[LoopDevice] Binding file %s to loop device %d\n", file->_path_name.c_str(), _loop_number);
